def isExist(nums, m):
    remain = set()
    remain.add(0)

    total = 0
    for num in nums:
        total += num
        if total % m in remain:
            return 1
        else:
            remain.add(total % m)

    return 0


# 输入获取
while True:
    try:
        n, m = map(int, input().split())
        nums = list(map(int, input().split()))
        print(isExist(nums, m))
    except ValueError:
        break
